css_snippet:
/* For body text, subtle adjustments often improve readability */
body {
  letter-spacing: 0.01em; /* or -0.005em for larger body fonts */
}

/* For large headlines, a slightly negative value can enhance aesthetics */
h1 {
  letter-spacing: -0.02em;
  font-weight: 700;
}

/* Be cautious with very small text */
small {
  letter-spacing: 0.02em; /* May need slight positive spacing */
}
